331	macro_rules! atomic {
332	    // If values of type `$t` can be transmuted into values of the primitive atomic type `$atomic`,
333	    // declares variable `$a` of type `$atomic` and executes `$atomic_op`, breaking out of the loop.
334	    (@check, $t:ty, $atomic:ty, $a:ident, $atomic_op:expr) => {
335	        if can_transmute::<$t, $atomic>() {
336	            let $a: &$atomic;
337	            break $atomic_op;
338	        }
339	    };
340	
341	    // If values of type `$t` can be transmuted into values of a primitive atomic type, declares
342	    // variable `$a` of that type and executes `$atomic_op`. Otherwise, just executes
343	    // `$fallback_op`.
344	    ($t:ty, $a:ident, $atomic_op:expr, $fallback_op:expr) => {
345	        loop {
346	            atomic!(@check, $t, AtomicUnit, $a, $atomic_op);
347	
348	            // Always use fallback for now on environments that do not support inline assembly.
349	            #[cfg(not(any(
350	                miri,
351	                crossbeam_loom,
352	                crossbeam_atomic_cell_force_fallback,
353	            )))]
354	            atomic_maybe_uninit::cfg_has_atomic_cas! {
355	                atomic_maybe_uninit::cfg_has_atomic_8! {
356	                    atomic!(@check, $t, atomic_maybe_uninit::AtomicMaybeUninit<u8>, $a, $atomic_op);
357	                }
358	                atomic_maybe_uninit::cfg_has_atomic_16! {
359	                    atomic!(@check, $t, atomic_maybe_uninit::AtomicMaybeUninit<u16>, $a, $atomic_op);
360	                }
361	                atomic_maybe_uninit::cfg_has_atomic_32! {
362	                    atomic!(@check, $t, atomic_maybe_uninit::AtomicMaybeUninit<u32>, $a, $atomic_op);
363	                }
364	                atomic_maybe_uninit::cfg_has_atomic_64! {
365	                    atomic!(@check, $t, atomic_maybe_uninit::AtomicMaybeUninit<u64>, $a, $atomic_op);
366	                }
367	                atomic_maybe_uninit::cfg_has_atomic_128! {
368	                    atomic!(@check, $t, atomic_maybe_uninit::AtomicMaybeUninit<u128>, $a, $atomic_op);
369	                }
370	            }
371	
372	            break $fallback_op;
373	        }
374	    };
375	}
