377	macro_rules! impl_arithmetic {
378	    ($t:ty, #[cfg($target_has_atomic:meta)] $atomic:ident, $example:tt) => {
379	        impl AtomicCell<$t> {
380	            /// Increments the current value by `val` and returns the previous value.
381	            ///
382	            /// The addition wraps on overflow.
383	            ///
384	            /// # Examples
385	            ///
386	            /// ```
387	            /// use crossbeam_utils::atomic::AtomicCell;
388	            ///
389	            #[doc = $example]
390	            ///
391	            /// assert_eq!(a.fetch_add(3), 7);
392	            /// assert_eq!(a.load(), 10);
393	            /// ```
394	            #[inline]
395	            pub fn fetch_add(&self, val: $t) -> $t {
396	                atomic! {
397	                    $t, _a,
398	                    {
399	                        #[cfg($target_has_atomic)]
400	                        {
401	                            let a = unsafe { &*(self.as_ptr() as *const atomic::$atomic) };
402	                            a.fetch_add(val, Ordering::AcqRel)
403	                        }
404	                        #[cfg(not($target_has_atomic))]
405	                        {
406	                            self.fetch_update(|old| Some(old.wrapping_add(val))).unwrap()
407	                        }
408	                    },
409	                    {
410	                        let _guard = lock(self.as_ptr() as usize).write();
411	                        let value = unsafe { &mut *(self.as_ptr()) };
412	                        let old = *value;
413	                        *value = value.wrapping_add(val);
414	                        old
415	                    }
416	                }
417	            }
418	
419	            /// Decrements the current value by `val` and returns the previous value.
420	            ///
421	            /// The subtraction wraps on overflow.
422	            ///
423	            /// # Examples
424	            ///
425	            /// ```
426	            /// use crossbeam_utils::atomic::AtomicCell;
427	            ///
428	            #[doc = $example]
429	            ///
430	            /// assert_eq!(a.fetch_sub(3), 7);
431	            /// assert_eq!(a.load(), 4);
432	            /// ```
433	            #[inline]
434	            pub fn fetch_sub(&self, val: $t) -> $t {
435	                atomic! {
436	                    $t, _a,
437	                    {
438	                        #[cfg($target_has_atomic)]
439	                        {
440	                            let a = unsafe { &*(self.as_ptr() as *const atomic::$atomic) };
441	                            a.fetch_sub(val, Ordering::AcqRel)
442	                        }
443	                        #[cfg(not($target_has_atomic))]
444	                        {
