949	/// Returns `true` if values of type `A` can be transmuted into values of type `B`.
950	const fn can_transmute<A, B>() -> bool {
951	    // Sizes must be equal, but alignment of `A` must be greater or equal than that of `B`.
952	    (mem::size_of::<A>() == mem::size_of::<B>()) & (mem::align_of::<A>() >= mem::align_of::<B>())
